sp_page.css:
/* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
      Container 2 Row has CSS selector row auto added to our ask of fill-section flex-row
        and we have to override the row style else we get a scrollbar at the bottom of the page
        see div.sp-row-content.fill-section.flex-row.row below
   !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!! */
div.sp-row-content.fill-section.flex-row.row,
div.sp-row-content.fill-section.flexbox.row {
  margin-left: 0;
  margin-right: 0;
}

/* Tasker Data Table */
.v1fe908a64fc71300d236eb118110c78a {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* Tasker Attachments */
.v5a5d0f5cdb81b300bb8ee536ca96193f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* flex sp-widget for DocInt List */
.v6dedb22adb9fdb0069d100b5ca96195f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

//---------------------------------------------------------------------------------
//KT Wrapping Table Headers Data Table (widget-data-table)
.v5001b062d7101200b0b044580e6103eb .th-title {
  display: inline-block;
  color: $primary;
  //KT
  white-space: normal;
}

.text-nowrap {
    white-space: normal;
}
//---------------------------------------------------------------------------------

.sp-attachments-input {
  visibility: hidden;
  position: absolute;
  left: 0px;
}


.file-selector {
  float: right;
  font-size: 24px;
  margin-top: -5px;
}
